from vex import Guard, verify
from agno.agent import Agent

class VoiceSafetyGuard(Guard):
    def __init__(self, session_history: list):
        self.history = session_history

    async def check(self, response: str, context: dict) -> bool:
        # Check toxicity, coherence with history, intent classification
        toxicity_score = await self._toxicity_check(response)
        coherence_score = self._check_coherence(response, self.history[-3:])
        return toxicity_score < 0.1 and coherence_score > 0.8

@verify(guards=[VoiceSafetyGuard(session_history)])
async def verified_voice_turn(agent: Agent, user_input: str, session_history: list):
    return await agent.run(user_input)
